const action = $json.query.action || 'campaigns';
const advertiserId = $json.query.advertiser_id || '50727';
const campaignId = $json.query.campaign_id || '';
const dateFrom = $json.query.date_from || '';
const dateTo = $json.query.date_to || '';
const limit = $json.query.limit || '50';
const offset = $json.query.offset || '0';

const METRICS = 'clicks,prints,ctr,cost,cpc,acos,roas,direct_amount,indirect_amount,total_amount,direct_units_quantity,indirect_units_quantity,units_quantity,cvr';
const metricsParams = (dateFrom && dateTo) 
  ? `&date_from=${dateFrom}&date_to=${dateTo}&metrics=${METRICS}&metrics_summary=true`
  : '';

let url = '';
if (action === 'advertiser') {
  url = `https://api.mercadolibre.com/advertising/advertisers?product_id=PADS`;
}
else if (action === 'campaigns') {
  url = `https://api.mercadolibre.com/advertising/advertisers/${advertiserId}/product_ads/campaigns?limit=${limit}&offset=${offset}${metricsParams}`;
}
else if (action === 'ads') {
  const campaignFilter = campaignId ? `&filters%5Bcampaign_id%5D=${campaignId}` : '';
  url = `https://api.mercadolibre.com/advertising/advertisers/${advertiserId}/product_ads/items?limit=${limit}&offset=${offset}${metricsParams}${campaignFilter}`;
}
else if (action === 'metrics') {
  url = `https://api.mercadolibre.com/advertising/advertisers/${advertiserId}/product_ads/campaigns?limit=${limit}&date_from=${dateFrom}&date_to=${dateTo}&metrics=${METRICS}&metrics_summary=true`;
}

return [{ json: { action, url, advertiserId, campaignId, dateFrom, dateTo } }];
